import {
  Component,
  HostBinding,
  OnDestroy,
  OnInit,
  Renderer2
} from '@angular/core';
import {UntypedFormControl, UntypedFormGroup, Validators} from '@angular/forms';
import {ToastrService} from 'ngx-toastr';
import { ApiService } from '@services/api.service';
import { AppService } from '@services/app.service';
import { ActivatedRoute, Router } from '@angular/router';


@Component({
  selector: 'app-changepassword',
  templateUrl: './changepassword.component.html',
  styleUrls: ['./changepassword.component.scss']
})
export class ChangepasswordComponent {

  @HostBinding('class') class = 'login-box';
  public changePasswordForm: UntypedFormGroup;
  public isAuthLoading = false;



  constructor(
      private renderer: Renderer2,
      private toastr: ToastrService,
      private appService: AppService,
      private api: ApiService,
      private route: ActivatedRoute,
      private router: Router
  ) { }

  ngOnInit(): void {
      this.renderer.addClass(
          document.querySelector('app-root'),
          'login-page'
      );
      this.changePasswordForm = new UntypedFormGroup({
        previous_password: new UntypedFormControl(null, [Validators.required]),
        new_password: new UntypedFormControl(null, [Validators.required])
      });   
  }


  ChangePassword(){
    const sub=this.api.ChangePassword(this.changePasswordForm.value.previous_password, this.changePasswordForm.value.new_password, )
    .subscribe((response: any) => {
        sub.unsubscribe();
        if(response?.status >= 400) {
          this.toastr.error(response.error.message)
          return;
        }
        this.toastr.success(response.message);
        this.router.navigate(['/login']);
      })
  }


  ResetPassword() {
    if (this.changePasswordForm.valid) {
    } else {
        this.toastr.error('Enter Valid Password');
    }
}


  ngOnDestroy(): void {
      this.renderer.removeClass(
          document.querySelector('app-root'),
          'login-page'
      );
  }

}


