import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute } from '@angular/router';
import { ApiService } from '@services/api.service';
import { AppService } from '@services/app.service';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';

@Component({
    selector: 'app-profile',
    templateUrl: './profile.component.html',
    styleUrls: ['./profile.component.scss']
})
export class ProfileComponent {
    posts: any;
    data: any;
    admin: any;

    isLoading : boolean = false;
    imageDynamicUrl: string;
    form: FormGroup;

    constructor(
        private api: ApiService, 
        private route: ActivatedRoute,
        private toastr: ToastrService,
        private fb: FormBuilder,
        private app: AppService
        ){
            this.form = this.fb.group({
                name: ['', [Validators.required]],
                image_url: [null],
                email: ['', [Validators.email, Validators.required]]
            })
      }

    ngOnInit() {
        this.AdminDetails()
    }

    AdminDetails(){
        const details = this.api.AdminDetails().subscribe((response: any) => {
            details.unsubscribe();
            const u : any = response.admin
            this.admin = response.admin
            this.imageDynamicUrl = this.admin.image.dynamic_url;
            this.form.setValue({
                name: this.admin.name,
                image_url: this.admin.image.orignal_url,
                email: this.admin.email
            })
        })
    }

    fileUpload(files: File[]) {
        this.isLoading = true;
        const sub = this.api.uploadSingleFile(files[0]).subscribe((response: any) => {
          sub.unsubscribe();
          this.isLoading = false;
          this.form.controls.image_url.setValue(response.urls.orignal_url);
          this.imageDynamicUrl = response.urls.dynamic_url;
        })
    }
  
    updateProfile() {
        const sub = this.api.updateAdminProfile(this.form.value)
        .pipe(
            catchError((err) => err)
        )
        .subscribe((response: any) => {
            sub.unsubscribe();
            this.isLoading = false;
            this.app.getProfile();
            if(response?.status >= 400) {
                this.toastr.error(response.error.message)
                return;
            }
            this.toastr.success( response.message )
        })
    }
}
