import {Component, NgModule} from '@angular/core';
import {Routes, RouterModule} from '@angular/router';
import {MainComponent} from '@modules/main/main.component';
import {LoginComponent} from '@modules/login/login.component';
import {ProfileComponent} from '@pages/profile/profile.component';
import {RegisterComponent} from '@modules/register/register.component';
import {DashboardComponent} from '@pages/dashboard/dashboard.component';
import {AuthGuard} from '@guards/auth.guard';
import {NonAuthGuard} from '@guards/non-auth.guard';
import {ForgotPasswordComponent} from '@modules/forgot-password/forgot-password.component';
import {RecoverPasswordComponent} from '@modules/recover-password/recover-password.component';
import { ResetpassComponent } from '@modules/resetpass/resetpass.component';
import { ChangepasswordComponent } from '@modules/changepassword/changepassword.component';
import { StripeComponent } from '@modules/stripe/stripe.component';


const routes: Routes = [
    {
        path: '',
        component: MainComponent,
        canActivate: [AuthGuard],
        canActivateChild: [AuthGuard],
        children: [
            {
                path: 'profile',
                component: ProfileComponent
            },
            {
                path: '',
                component: DashboardComponent
            },
            {
                path: 'admins',
                loadChildren: () => import('./pages/admin/admin.module').then((m) => m.AdminModule)
            },
            {
                path: 'orders',
                loadChildren: () => import('./pages/orders/orders.module').then((m) => m.OrdersModule)
            },
            {
                path: 'users',
                loadChildren: () => import('./pages/users/users.module').then((m) => m.UsersModule)
            },
            {
                path: 'stores',
                loadChildren: () => import('./pages/store/store.module').then(m => m.StoreModule)
            },
            {
                path: 'pages',
                loadChildren: () => import('./pages/page/page.module').then(m => m.PageModule)
            },
            {
                path: 'categories',
                loadChildren: () => import('./pages/category/category.module').then(m => m.CategoryModule)
            },  
            {
                path: 'products',
                loadChildren: () => import('./pages/products/products.module').then(m => m.ProductsModule)
            },
            {
                path: 'settings',
                loadChildren: () => import('./pages/settings/settings.module').then(m=> m.SettingsModule)
            }
            ,
            {
                path: 'claim',
                loadChildren: () => import('./pages/claim-store/claim-store.module').then(m=> m.ClaimStoreModule)
            },
            {
                path: 'memberships',
                loadChildren: () => import('./pages/memberships/memberships.module').then(m=> m.MembershipsModule)
            },
            {
                path: 'reports',
                loadChildren: () => import('./pages/reports/reports.module').then(m => m.ReportsModule)
            }
            
        ]
    },

    {
        path: 'stripe',
        component: StripeComponent
    } ,
    {
        path: 'login',
        component: LoginComponent,
        canActivate: [NonAuthGuard]
    },
    {
        path: 'register',
        component: RegisterComponent,
        canActivate: [NonAuthGuard]
    },
    {
        path: 'forgot-password',
        component: ForgotPasswordComponent,
        canActivate: [NonAuthGuard]
    },
    {
        path: 'resetpass',
        component: ResetpassComponent,
        canActivate: [NonAuthGuard]
    },
    {
        path: 'changepassword',
        component: ChangepasswordComponent,
        canActivate: [AuthGuard]
    },
    {
        path: 'recover-password',
        component: RecoverPasswordComponent,
        canActivate: [NonAuthGuard]
    },
    {path: '**', redirectTo: ''}
];

@NgModule({
    imports: [RouterModule.forRoot(routes, {})],
    exports: [RouterModule]
})
export class AppRoutingModule {}
