import {Component, ViewChild} from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { delay, map, merge, startWith, switchMap, tap } from 'rxjs';
import { ApiService } from '@services/api.service';
@Component({
    selector: 'app-notifications',
    templateUrl: './notifications.component.html',
    styleUrls: ['./notifications.component.scss']
})
export class NotificationsComponent {

  unreadCount: number = 0;
  notifications: any[] = [];

  constructor(private api: ApiService) {
      
  }


  ngAfterViewInit() {
    const countSub = this.api.unreadNotificationCount().subscribe((response: any) => {
      countSub.unsubscribe();
      this.unreadCount = response.unread_count;
    })
  }

  showNotifications() {
    const notifSub = this.api.notificationList(1, 5, 'admin_notification_id', 'DESC').subscribe((response: any) => {
      notifSub.unsubscribe();
      this.notifications = response.admin_notifications;
      this.ngAfterViewInit()
    })
  }


}




    
  

   



