import { Inject, Injectable, PLATFORM_ID } from '@angular/core';
import { HttpEvent, HttpInterceptor, HttpHandler, HttpRequest, HttpResponse, HttpErrorResponse, HttpHeaders } from '@angular/common/http';
import { catchError, finalize, map, mergeMap, Observable, of, throwError } from 'rxjs';
import { Router } from '@angular/router';
import { isPlatformBrowser } from '@angular/common';
import { ToastrService } from 'ngx-toastr';


@Injectable({
  providedIn: 'root'
})
export class ApiInterceptorService implements HttpInterceptor {

  constructor(
    private _toast: ToastrService, 
    private _router: Router,
    @Inject(PLATFORM_ID) private _platformId: string) { }
  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {

    const getHeaders = () => {
      let headers: any = {};
      if(isPlatformBrowser(this._platformId)) {
        if (localStorage.getItem('token')) {
          const token = localStorage.getItem('token');
          headers['Authorization'] = `Bearer ${token}`;
        }
      }
      return headers;
    }

    const _req = req.clone({setHeaders: {...getHeaders()}});
    
    
    return next.handle(_req).pipe(
      map((evt: any) => {
        if (evt instanceof HttpResponse) {
          if (evt.body && evt.body.message){
            // this._toast.showSuccessToast(evt.body.message);
            // now clone the data and replace it with evt.body.data with evt.body
            evt = evt.clone();
            evt.body = {...evt.body.data,message: evt.body.message};
          }
        }
        return evt;
      }),
      catchError((err: any) => {
        if(err instanceof HttpErrorResponse) {
          if(err.status == 401) {
            if(isPlatformBrowser(this._platformId)) {
              localStorage.removeItem('token');
            }
            this._router.navigate(['/login']);
          }
        }
        return throwError(() => of(err));
      })
    );
  }
}